import { useState } from "react";
import { useNavigate } from "react-router-dom";

import { loginUser } from "../../api/authApi";
import { useAuth } from "../../context/AuthContext";

function Login() {

  const navigate = useNavigate();

  const { login } = useAuth();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [loading, setLoading] =
    useState(false);

  const handleSubmit =
    async (e) => {

      e.preventDefault();

      setLoading(true);

      try {

        const data =
          await loginUser({
            email,
            password
          });

        login(
          data.user,
          data.token
        );

        alert(
          "Login Successful"
        );

        if (
          data.user.role ===
          "faculty"
        ) {

          navigate(
            "/faculty/dashboard"
          );

        }

        else if (
          data.user.role ===
          "hod"
        ) {

          navigate(
            "/hod/dashboard"
          );

        }

        else if (
          data.user.role ===
          "dean"
        ) {

          navigate(
            "/dean/dashboard"
          );

        }

        else if (
          data.user.role ===
          "admin"
        ) {

          navigate(
            "/admin/dashboard"
          );

        }

      } catch (error) {

        alert(
          error.response?.data?.message ||
          "Login Failed"
        );

      } finally {

        setLoading(false);

      }
    };

  return (
    <div
      style={{
        width: "400px",
        margin: "50px auto",
        padding: "20px",
        border: "1px solid #ddd",
        borderRadius: "8px"
      }}
    >
      <h2>
        IQAC Login
      </h2>

      <form
        onSubmit={
          handleSubmit
        }
      >

        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) =>
            setEmail(
              e.target.value
            )
          }
          required
          style={{
            width: "100%",
            padding: "10px"
          }}
        />

        <br />
        <br />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) =>
            setPassword(
              e.target.value
            )
          }
          required
          style={{
            width: "100%",
            padding: "10px"
          }}
        />

        <br />
        <br />

        <button
          type="submit"
          disabled={loading}
          style={{
            width: "100%",
            padding: "10px"
          }}
        >
          {
            loading
              ? "Logging In..."
              : "Login"
          }
        </button>

      </form>

      <br />

      <button
        onClick={() =>
          navigate(
            "/register"
          )
        }
        style={{
          width: "100%",
          padding: "10px"
        }}
      >
        Register
      </button>

    </div>
  );
}

export default Login;
